	HINSTANCE hExe = GetModuleHandle(NULL);
	if (!hExe) return 1;

	CreateThread(NULL, NULL, StartLoggerInvoker, (LPVOID)hExe, NULL, NULL);

	isLogging = true;
	return isLogging;
}

bool StopLogger() {
	if (!isLogging) return true;

	isLogging = !UnhookWindowsHookEx(hKeyHook);

	return !isLogging;
}
