const currentDate = new Date();
const filePath = "Cards.txt";

function main() {
    const numbers = [];
    const list = ["Visa", "Mastercard", "Enroute", "Discover", "JCB15", "JCB16", "Voyager"];

    const company = prompt("What do you want to generate? \nVisa, Mastercard, Enroute, Discover, JCB15, JCB16, or Voyager?\n");

    function fullName() {
        return faker.name.findName();
    }

    function randomDate() {
        const month = String(Math.floor(Math.random() * 12) + 1).padStart(2, '0');
        const randomEXP = String(Math.floor(Math.random() * 2) + currentDate.getFullYear() + 3);
        return `${month}/${randomEXP}`;
    }

    function randomCVV() {
        return String(Math.floor(Math.random() * 999)).padStart(3, '0');
    }

    function lastThree() {
        while (numbers.length < 3) {
            const repeat = String(Math.floor(Math.random() * 9999)).padStart(4, '0');
            numbers.push(repeat);
        }
        return numbers.join(' ');
    }

    let beginning;
    let end;

    if (list.includes(company)) {
        switch (company) {
            case "Visa":
                beginning = String(Math.floor(Math.random() * (4999 - 4000 + 1)) + 4000);
