                break;
            case "Mastercard":
                beginning = String(Math.floor(Math.random() * (5599 - 5100 + 1)) + 5100);
                end = `Mastercard: ${fullName()} | ${beginning} ${lastThree()} | ${randomDate()} | ${randomCVV()}`;
