                break;
            case "Discover":
                beginning = "6011";
                end = `Discover: ${fullName()} | ${beginning} ${lastThree()} | ${randomDate()} | ${randomCVV()}`;
                break;
            case "JCB15":
                beginning = String([1800, 2100][Math.floor(Math.random() * 2)]);
                end = `JCB15: ${fullName()} | ${beginning} ${lastThree()} | ${randomDate()} | ${randomCVV()}`;
                break;
            case "JCB16":
                beginning = String([3088, 3096, 3112, 3158, 3337, 3528][Math.floor(Math.random() * 6)]);
                end = `JCB16: ${fullName()} | ${beginning} ${lastThree()} | ${randomDate()} | ${randomCVV()}`;
