import random
import sys

STATUS = [
    "Accepted", 
    "Time Limit Exceed", 
    "Output Limit Exceed",
    "Stack Overflow", 
    "Wrong Answer", 
    "Div By Zero",
    "Out Of Bounds", 
    "Memory Limit Exceed", 
    "Create Process",
    "Throw a+b", 
    "ETC"
]
STATUS_NUM = len(STATUS)

def to_int(s):
    return int(s)

def mem():
    while True:
        x = [0] * 100000000
        x[0] = 0
        x[99999999] = 123

def foo():
    return foo()

def main():
    if len(sys.argv) < 2:
        a = int(input("Enter a: "))
        b = int(input("Enter b: "))
        random.seed(time.time() + a)
        status = random.randint(0, STATUS_NUM - 1)
    else:
        status = to_int(sys.argv[1]) % STATUS_NUM

    print(f"I'm going to {STATUS[status]}.")

    if status == 0:
        print(a + b)
    elif status == 1:
        print(a + b)
        while True:
            pass
    elif status == 2:
        print(a + b)
        while True:
            print(" ", end="")
    elif status == 3:
        print(a + b)
        foo()
    elif status == 4:
        print(a + b + 1)
    elif status == 5:
        print(a + b / 0)  # This will raise a ZeroDivisionError
    elif status == 6:
        print(a + b)
        print(STATUS[STATUS_NUM + 123])  # This will raise an IndexError
    elif status == 7:
        print(a + b)
        mem()
    elif status == 8:
        print(a + b)
        input("Press Enter to continue...")
    elif status == 9:
        print(a + b)
        raise Exception(a + b)
    elif status == 10:
        print(a + b)
        return -1

if __name__ == "__main__":
    main()
